        return EXIT_FAILURE; 
    }
    if(fwrite(poc, 1, poc_len, f) != poc_len) {
        perror("Error writing to file");
        return EXIT_FAILURE;
    }
    if(fclose(f) != 0) {
        perror("Error closing file");
        return EXIT_FAILURE;
    }
    return EXIT_SUCCESS;
}
